function _normAirServiceCode(code) {
  return String(code || '').toUpperCase().replace(/[^A-Z0-9]/g, '');
}

function _airServiceMatches(rule, serviceCode) {
  const code = _normAirServiceCode(serviceCode);
  const aliases = [rule.serviceCode].concat(rule.aliases || []);
  return aliases.some(alias => _normAirServiceCode(alias) === code);
}

function _airRuleMatchesEntry(rule, entry) {
  if (!entry || !entry.zip) return false;
  const zip = String(entry.zip).padStart(5, '0');
  const prefix3 = zip.slice(0, 3);
  if (rule.stateFilter && !rule.stateFilter.includes(entry.state)) return false;
  if (rule.prefixFilter && !zip.startsWith(rule.prefixFilter)) return false;
  if (rule.prefixList && !rule.prefixList.some(p => zip.startsWith(p))) return false;
  if (rule.prefixMin && prefix3 < String(rule.prefixMin)) return false;
  if (rule.prefixMax && prefix3 > String(rule.prefixMax)) return false;
  return true;
}

function resolveAirSort(entryOrZip, serviceCode) {
  const entry = typeof entryOrZip === 'string'
    ? { zip: entryOrZip, state: '' }
    : (entryOrZip || {});
  const rule = AIR_SORT_RULES.find(r =>
    _airServiceMatches(r, serviceCode) && _airRuleMatchesEntry(r, entry));
  if (!rule) return null;
  return {
    serviceCode: rule.serviceCode,
    service: rule.service,
    belt: rule.belt,
    beltName: BELT_NAMES[rule.belt],
    level: rule.level || null,
    intl: !!rule.intl,
    satNote: !!rule.satNote,
  };
}

