// Helper: split belt code and name from "PD-XX · Description"
function beltCode(idx) {
  const name = BELT_NAMES[idx] || '';
  return name.split(' · ')[0] || name;
}
function beltDesc(idx) {
  const name = BELT_NAMES[idx] || '';
  return name.split(' · ')[1] || '';
}
